interface ReportsPageProps {
  onLoadAction: 'print' | null;
  onActionComplete: () => void;
}

export const ReportsPage: React.FC<ReportsPageProps> = ({ onLoadAction, onActionComplete }) => {
  const [isExportingCSV, setIsExportingCSV] = useState(false);
  const [isExportingPDF, setIsExportingPDF] = useState(false);

  useEffect(() => {
    if (onLoadAction === 'print') {
      handleExportPDF();
      onActionComplete();
    }
  }, [onLoadAction]);


  const fetchExportDataFromBackend = async () => {
    return new Promise((resolve) => {
      setTimeout(() => {
        const fullData = annualHistory.map(item => ({
          ...item,
          balance: item.income - item.expense,
          status: 'FECHADO',
          date: `01/2024`
        }));
        resolve(fullData);
      }, 1200);
    });
  };

  const handleExportCSV = async () => {
    try {
      setIsExportingCSV(true);
      const data: any = await fetchExportDataFromBackend();
      const headers = ['Mês', 'Receitas (MZN)', 'Despesas (MZN)', 'Saldo Líquido (MZN)', 'Status de Fechamento'];
      const rows = data.map((item: any) => [
        item.month,
        item.income.toFixed(2),
        item.expense.toFixed(2),
        item.balance.toFixed(2),
        item.status
      ]);

      const csvContent = [headers.join(';'), ...rows.map((row: any) => row.join(';'))].join('\n');
      const BOM = '\uFEFF';
      const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `FINTECH_Relatorio_Financeiro_${new Date().getTime()}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error(error);
    } finally {
      setIsExportingCSV(false);
    }
  };

  const handleExportPDF = () => {
    setIsExportingPDF(true);
    setTimeout(() => {
      window.print();
      setIsExportingPDF(false);
    }, 300);
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 no-print">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Inteligência de Dados</h2>
          <p className="text-slate-500 font-medium">Exporte relatórios consolidados para apresentações ou auditoria.</p>
        </div>
        <div className="flex flex-wrap gap-3">
           <button 
             onClick={handleExportCSV}
             disabled={isExportingCSV}
             className="px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all shadow-sm flex items-center gap-3 disabled:opacity-50 active:scale-95"
           >
              {isExportingCSV ? (
                <div className="w-4 h-4 border-2 border-slate-300 border-t-orange-600 rounded-full animate-spin"></div>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
              )}
              {isExportingCSV ? 'Processando...' : 'Baixar CSV'}
           </button>

           <button 
             onClick={handleExportPDF}
             disabled={isExportingPDF}
             className="px-6 py-4 bg-orange-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-orange-600 transition-all shadow-xl shadow-orange-500/20 flex items-center gap-3 disabled:opacity-50 active:scale-95"
           >
              {isExportingPDF ? (
                <div className="w-4 h-4 border-2 border-orange-300 border-t-white rounded-full animate-spin"></div>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9V2h12v7"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
